    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Web Content Filter (Adult/Category)",
        "items": [
          {
            "type": 1,
            "content": { "json": "Microsoft Defender Web Content Filtering (Network Protection) categorizes the destination (e.g. *Adult content*, *Pornography*, *Nudity*, *Gambling*, *Dating*, *Liability*, *Hate*, etc.). These events appear in `DeviceEvents` with `ActionType == \"ExploitGuardNetworkProtectionBlocked\"` and the category sits in `AdditionalFields.ResponseCategory`." },
            "name": "wc-text"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let urlFilter = '{UrlContains}';\r\nDeviceEvents\r\n| where ActionType == \"ExploitGuardNetworkProtectionBlocked\"\r\n| where \"*\" in ('{DeviceName}') or DeviceName in ('{DeviceName}')\r\n| where \"*\" in ('{UserUPN}')   or InitiatingProcessAccountUpn in ('{UserUPN}')\r\n| where isempty(urlFilter) or RemoteUrl has urlFilter\r\n| extend P = parse_json(AdditionalFields)\r\n| extend WebCategory = tostring(P.ResponseCategory)\r\n| where isnotempty(WebCategory)\r\n| summarize count() by WebCategory, bin(TimeGenerated, 1h)",
              "size": 0,
              "title": "Web Content Filter blocks by Category",
              "timeContextFromParameter": "TimePicker",
              "timeBrushParameterName": "TimeBrushWC",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "timechart"
            },
            "name": "wc-chart"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let urlFilter = '{UrlContains}';\r\nDeviceEvents\r\n| where ActionType == \"ExploitGuardNetworkProtectionBlocked\"\r\n| where \"*\" in ('{DeviceName}') or DeviceName in ('{DeviceName}')\r\n| where \"*\" in ('{UserUPN}')   or InitiatingProcessAccountUpn in ('{UserUPN}')\r\n| where isempty(urlFilter) or RemoteUrl has urlFilter\r\n| extend P = parse_json(AdditionalFields)\r\n| extend WebCategory   = tostring(P.ResponseCategory),\r\n         ParentCategory = tostring(P.ResponseCategoryGroup),\r\n         IsAudit        = tobool(P.IsAudit)\r\n| where isnotempty(WebCategory)\r\n| project TimeGenerated, DeviceName, User = InitiatingProcessAccountUpn, BlockedUrl = RemoteUrl, WebCategory, ParentCategory, IsAudit, InitiatingProcessFileName, InitiatingProcessCommandLine\r\n| sort by TimeGenerated desc",
              "size": 2,
              "title": "Web Content Filter events",
              "timeContextFromParameter": "TimeBrushWC",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "rowLimit": 3000,
                "formatters": [
                  { "columnMatch": "WebCategory", "formatter": 1 }
                ]
              }
            },
            "name": "wc-grid"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let urlFilter = '{UrlContains}';\r\nDeviceEvents\r\n| where ActionType == \"ExploitGuardNetworkProtectionBlocked\"\r\n| where \"*\" in ('{DeviceName}') or DeviceName in ('{DeviceName}')\r\n| where \"*\" in ('{UserUPN}')   or InitiatingProcessAccountUpn in ('{UserUPN}')\r\n| where isempty(urlFilter) or RemoteUrl has urlFilter\r\n| extend P = parse_json(AdditionalFields)\r\n| extend WebCategory = tostring(P.ResponseCategory)\r\n| where WebCategory has_any (\"Adult\",\"Pornography\",\"Nudity\",\"Sexually\",\"Mature\",\"Gambling\",\"Dating\")\r\n| extend Domain = tolower(tostring(parse_url(RemoteUrl).Host))\r\n| summarize Hits = count(), Devices = dcount(DeviceName), LastSeen = max(TimeGenerated), SampleUrls = make_set(RemoteUrl, 5) by User = InitiatingProcessAccountUpn, WebCategory, Domain\r\n| where isnotempty(User)\r\n| order by Hits desc",
              "size": 2,
              "title": "Adult / NSFW / Gambling — by User & Domain",
              "timeContextFromParameter": "TimePicker",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": { "rowLimit": 500 }
            },
